#include <stdio.h>
#include <string.h>

char* countAndSay(int n) {
    char result[10000] = "1";
    int len = 1;
    for (int i = 1; i < n; i++) {
        char current[10000] = "";
        int count = 1;
        for (int j = 1; j <= len; j++) {
            if (result[j] == result[j - 1]) {
                count++;
            } else {
                sprintf(current + strlen(current), "%d%c", count, result[j - 1]);
                count = 1;
            }
        }
        strcpy(result, current);
        len = strlen(result);
    }
    return result;
}

int main() {
    int n = 5;
    printf("Count and Say term %d: %s\n", n, countAndSay(n));
    return 0;
}

