    string countAndSay(int n) {
        string result = "1";

        // Generate the sequence up to the nth term
        for (int i = 1; i < n; ++i) {
            string current = "";
            int count = 1;

            // Traverse the previous result
            for (int j = 1; j < result.size(); ++j) {
